import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { BarChart } from '@mui/x-charts';
import response from './response.json';

interface HourlyForecast {
  hour: string;
  uvLevel: number;
}

interface UVData {
  location: string;
  current: {
    uvLevel: number;
    riskCategory: string;
  };
  hourlyForecast: HourlyForecast[];
}

export default function Widget() {
  const uvData = response.data as UVData;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 450, bgcolor: '#FFF3E0' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" color="text.secondary">
              {uvData.location}
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: '#FF5722' }}>
              UV Index: {uvData.current.uvLevel}
            </Typography>
            <Chip label={uvData.current.riskCategory} sx={{ bgcolor: '#FFC107', color: '#FFFFFF', fontWeight: 'bold' }} />
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <BarChart
              height={140}
              series={[
                {
                  data: uvData.hourlyForecast.map((f) => f.uvLevel),
                  color: '#FF5722',
                },
              ]}
              xAxis={[
                {
                  data: uvData.hourlyForecast.map((f) => f.hour),
                  scaleType: 'band',
                  tickLabelStyle: {
                    fontSize: 11,
                    fill: '#6B7280',
                  },
                },
              ]}
              margin={{ top: 10, bottom: 30, left: 40, right: 10 }}
              sx={{
                '& .MuiBarElement-root': {
                  rx: 4,
                },
              }}
            />
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
